class LoginPage:
    def __init__(self):
        self.auth = False
    def submit(self, user, password):
        self.auth = user == 'ana' and password == 'x'
        return self.auth

p = LoginPage()
print(p.submit('ana', 'x'))

def should_retry(k):
    return k in {'timeout', '429'}

for k in ['timeout','captcha','429']:
    print(k, should_retry(k))
